return {
  triggerSource: 'manual',
  channel: 'manualTrigger',
  commandText: 'status sprint',
  actorId: 'manual-trigger',
  actorDisplayName: 'Manual Trigger',
  spaceId: 'manual-trigger-space',
  threadKey: 'manual-check-sprint',
  sessionId: 'manual-trigger-space:manual-check-sprint',
};

return {
  triggerSource: 'schedule',
  channel: 'system',
  commandText: 'check sprint',
  actorId: 'schedule-trigger',
  actorDisplayName: 'Schedule Trigger',
  spaceId: 'system-schedule',
  threadKey: '',
  sessionId: 'system-schedule:check-sprint',
};

const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const message = body.message && typeof body.message === 'object' ? body.message : {};
const space = body.space && typeof body.space === 'object' ? body.space : (message.space || {});
const thread = message.thread && typeof message.thread === 'object' ? message.thread : (body.thread || {});
const threadName = String(thread.name || '').trim();
const threadKey = threadName
  ? threadName.split('/').pop()
  : String(message.name || body.messageId || body.eventTime || 'google-chat-thread').trim();

let commandText = String(
  message.argumentText ||
    message.slashCommand?.commandName ||
    message.text ||
    ''
).trim();

commandText = commandText
  .replace(/<users\/[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const spaceId = String(space.name || '').trim();
const sessionId = `${spaceId || 'google-chat'}:${threadKey || 'thread'}`;

return {
  triggerSource: 'chat',
  channel: 'googleChat',
  commandText,
  actorId: String(body.user?.name || message.sender?.name || '').trim(),
  actorDisplayName: String(body.user?.displayName || message.sender?.displayName || '').trim(),
  spaceId,
  threadKey,
  sessionId,
};

const event = $('Config Main').first().json || {};
const sessionResult = $input.first()?.json || {};
const session = sessionResult.found ? sessionResult.row : null;
const config = event.config || {};
const stableCommands = Array.isArray(config.stableCommands)
  ? config.stableCommands
  : ['check sprint', 'status sprint'];
const demoCommands = Array.isArray(config.demoCommands)
  ? config.demoCommands
  : ['release sprint', 'approve', 'reject', 'cancel'];
const memoryMaxTurns = Math.max(1, Number(config.memoryMaxTurns || 10));
const memoryUserChars = Math.max(40, Number(config.memoryUserChars || 180));
const memoryAssistantChars = Math.max(40, Number(config.memoryAssistantChars || 280));

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value).trim();
}

function trimText(value, maxLen) {
  const text = toText(value).replace(/\s+/g, ' ');
  if (!text) return '';
  if (!maxLen || text.length <= maxLen) return text;
  return `${text.slice(0, maxLen - 3).trimEnd()}...`;
}

function normalizeTurns(rawTurns) {
  if (!Array.isArray(rawTurns)) return [];

  return rawTurns
    .map((turn) => ({
      user: trimText(turn?.user || '', memoryUserChars),
      assistant: trimText(turn?.assistant || '', memoryAssistantChars),
      at: toText(turn?.at || ''),
    }))
    .filter((turn) => turn.user || turn.assistant)
    .slice(-memoryMaxTurns);
}

function parseMemory(rawCurrentIntent) {
  const raw = toText(rawCurrentIntent);
  if (!raw) {
    return {
      intent: '',
      previousIntent: '',
      turns: [],
      memoryUpdatedAt: '',
    };
  }

  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') {
      return {
        intent: '',
        previousIntent: '',
        turns: [],
        memoryUpdatedAt: '',
      };
    }

    return {
      intent: toText(parsed.intent),
      previousIntent: toText(parsed.previousIntent),
      turns: normalizeTurns(parsed.turns),
      memoryUpdatedAt: toText(parsed.memoryUpdatedAt),
    };
  } catch (error) {
    return {
      intent: '',
      previousIntent: '',
      turns: [],
      memoryUpdatedAt: '',
    };
  }
}

const memory = parseMemory(session?.currentIntent || '');
const sessionSummaryLines = session
  ? [
      `- currentIntent: ${memory.intent || 'unknown'}`,
      `- turnCount: ${memory.turns.length}`,
      `- activePendingActionId: ${toText(session.activePendingActionId) || 'none'}`,
      `- updatedAt: ${toText(session.updatedAt) || 'unknown'}`,
    ]
  : ['- no existing session state'];

const recentTurnsForPrompt = memory.turns.slice(-memoryMaxTurns).map((turn, index) => {
  const user = trimText(turn.user, 120) || '-';
  const assistant = trimText(turn.assistant, 160) || '-';
  return `${index + 1}. U: ${user} | A: ${assistant}`;
});

const chatInput = [
  `User: ${toText(event.actorDisplayName || event.actorId || 'Unknown')}`,
  `Channel: ${toText(event.channel || 'googleChat')}`,
  `Thread: ${toText(event.threadKey || 'thread')}`,
  `Message: ${toText(event.commandText)}`,
  '',
  'Current session state:',
  sessionSummaryLines.join('\n'),
  '',
  'Simple memory:',
  `- intent: ${memory.intent || 'none'}`,
  `- previousIntent: ${memory.previousIntent || 'none'}`,
  `- memoryUpdatedAt: ${memory.memoryUpdatedAt || 'none'}`,
  `- turnCount: ${memory.turns.length}`,
  '- recentTurns:',
  recentTurnsForPrompt.length ? recentTurnsForPrompt.join('\n') : 'none',
  '',
  `Stable commands: ${stableCommands.join(', ')}`,
  `Demo commands: ${demoCommands.join(', ')}`,
].join('\n');

return [
  {
    json: {
      sessionId: event.sessionId || session?.sessionId || '',
      session,
      memory,
      chatInput,
    },
  },
];

const context = $('Build Assistant Context').first().json || {};
const event = $('Config Main').first().json || {};
const config = event.config || {};
const agent = $input.first()?.json || {};

const stableCommands = Array.isArray(config.stableCommands)
  ? config.stableCommands
  : ['check sprint', 'status sprint'];
const demoCommands = Array.isArray(config.demoCommands)
  ? config.demoCommands
  : ['release sprint', 'approve', 'reject', 'cancel'];
const memoryMaxTurns = Math.max(1, Number(config.memoryMaxTurns || 10));
const memoryUserChars = Math.max(40, Number(config.memoryUserChars || 180));
const memoryAssistantChars = Math.max(40, Number(config.memoryAssistantChars || 280));
const configuredGgChatWebhookUrl = toText(config.ggChatWebhookUrl || '');

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value).trim();
}

function trimText(value, maxLen) {
  const text = toText(value).replace(/\s+/g, ' ');
  if (!text) return '';
  if (!maxLen || text.length <= maxLen) return text;
  return `${text.slice(0, maxLen - 3).trimEnd()}...`;
}

function normalizeTurns(rawTurns) {
  if (!Array.isArray(rawTurns)) return [];

  return rawTurns
    .map((turn) => ({
      user: trimText(turn?.user || '', memoryUserChars),
      assistant: trimText(turn?.assistant || '', memoryAssistantChars),
      at: toText(turn?.at || ''),
    }))
    .filter((turn) => turn.user || turn.assistant)
    .slice(-memoryMaxTurns);
}

function detectIntent(commandText) {
  const normalized = String(commandText || '').trim().toLowerCase();

  if (/release\s+sprint|close\s+sprint|release\s+status/.test(normalized)) return 'releaseDemo';
  if (/(^|\b)(approve|ok|dong y|đồng ý|xac nhan|xác nhận)(\b|$)/i.test(normalized)) return 'approveDemo';
  if (/(^|\b)(reject|tu choi|từ chối)(\b|$)/i.test(normalized)) return 'rejectDemo';
  if (/(^|\b)(cancel|huy|hủy)(\b|$)/i.test(normalized)) return 'cancelDemo';
  if (/check\s+sprint|status\s+sprint|sprint\s+status|healthcheck/.test(normalized)) return 'checkSprint';
  if (/(^|\b)(hello|hi|alo|chào|xin chào|cảm ơn|thanks|thank you)(\b|$)/i.test(normalized)) return 'smallTalk';

  return 'help';
}

function extractJsonText(value) {
  const text = toText(value);
  if (!text) return '';

  const fencedMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fencedMatch?.[1]) return fencedMatch[1].trim();

  if (text.startsWith('{') || text.startsWith('[')) return text;

  const firstBraceIndex = text.indexOf('{');
  const lastBraceIndex = text.lastIndexOf('}');
  if (firstBraceIndex >= 0 && lastBraceIndex > firstBraceIndex) {
    return text.slice(firstBraceIndex, lastBraceIndex + 1).trim();
  }

  const firstBracketIndex = text.indexOf('[');
  const lastBracketIndex = text.lastIndexOf(']');
  if (firstBracketIndex >= 0 && lastBracketIndex > firstBracketIndex) {
    return text.slice(firstBracketIndex, lastBracketIndex + 1).trim();
  }

  return '';
}

function tryParseJson(value) {
  const text = extractJsonText(value);
  if (!text || (!text.startsWith('{') && !text.startsWith('['))) return null;

  try {
    return JSON.parse(text);
  } catch (error) {
    return null;
  }
}

function normalizeStructuredCandidate(candidate) {
  if (!candidate) return null;
  if (typeof candidate === 'string') return tryParseJson(candidate);
  if (typeof candidate === 'object') return candidate;
  return null;
}

function isStructuredToolResult(candidate) {
  return Boolean(
    candidate &&
      typeof candidate === 'object' &&
      (candidate.deliveryPlan || candidate.resultText || candidate.toolName)
  );
}

function normalizeDestinationList(rawDestinations) {
  if (!Array.isArray(rawDestinations)) return [];

  const normalized = [];
  const seen = new Set();
  for (const rawDestination of rawDestinations) {
    const type = toText(rawDestination?.type || rawDestination);
    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }

  return normalized;
}

function defaultDestinationsForChannel(channel) {
  if (toText(channel) === 'system') {
    return [{ type: 'pushGoogleChat' }];
  }

  return [{ type: 'reply' }];
}

function filterAvailableDestinations(destinations) {
  const filtered = destinations.filter((destination) => {
    if (destination.type === 'pushGoogleChat' && !configuredGgChatWebhookUrl) return false;
    return true;
  });

  if (filtered.length > 0) return filtered;
  return [{ type: 'reply' }];
}

function normalizeMessageDestinations(rawDestinations, allowedTypes) {
  if (!Array.isArray(rawDestinations)) return allowedTypes;

  const requested = [];
  const seen = new Set();
  for (const rawDestination of rawDestinations) {
    const type = toText(rawDestination);
    if (!type || seen.has(type)) continue;
    seen.add(type);
    requested.push(type);
  }

  if (requested.length === 0) return allowedTypes;
  return requested.filter((type) => allowedTypes.includes(type));
}

function normalizeMessage(message, fallbackText, allowedTypes) {
  if (!message || typeof message !== 'object') return null;

  const payload = message.payload && typeof message.payload === 'object'
    ? message.payload
    : (toText(message.text || fallbackText) ? { text: toText(message.text || fallbackText) } : null);

  if (!payload) return null;

  const destinations = normalizeMessageDestinations(
    Array.isArray(message.destinations) ? message.destinations : message.destinationTypes,
    allowedTypes,
  );

  if (destinations.length === 0) return null;

  return {
    messageKey: toText(message.messageKey || message.key || 'reply') || 'reply',
    type: toText(message.type || (payload.cardsV2 ? 'googleChatCardV2' : 'text')) || 'text',
    destinations,
    payload,
  };
}

function normalizeDeliveryPlan(rawPlan, fallbackText) {
  const requestedDestinations = normalizeDestinationList(rawPlan?.destinations);
  const baseDestinations = requestedDestinations.length > 0
    ? requestedDestinations
    : defaultDestinationsForChannel(event.channel || 'googleChat');
  const destinations = filterAvailableDestinations(baseDestinations);
  const allowedTypes = destinations.map((destination) => destination.type);

  const messages = Array.isArray(rawPlan?.messages)
    ? rawPlan.messages
        .map((message) => normalizeMessage(message, fallbackText, allowedTypes))
        .filter(Boolean)
    : [];

  if (messages.length === 0 && allowedTypes.length > 0) {
    messages.push({
      messageKey: 'reply',
      type: 'text',
      destinations: allowedTypes,
      payload: { text: fallbackText },
    });
  }

  const thread = rawPlan?.thread && typeof rawPlan.thread === 'object'
    ? rawPlan.thread
    : (toText(event.channel) === 'system'
      ? { mode: 'singleThread', threadKeyHint: 'momo-ai-assistant-system' }
      : { mode: 'reply' });

  return {
    thread,
    destinations,
    messages,
  };
}

function getExecutedNodeJson(nodeName) {
  try {
    const nodeOutput = $(nodeName).first();
    return nodeOutput?.json && typeof nodeOutput.json === 'object' ? nodeOutput.json : null;
  } catch (error) {
    return null;
  }
}

const rawOutput =
  agent.output ??
  agent.response ??
  agent.result ??
  agent.text ??
  agent.message?.content ??
  '';
const routerToolOutput = getExecutedNodeJson('Assistant Command Router Workflow Tool');
const structuredOutput = [
  routerToolOutput,
  agent.output,
  agent.response,
  agent.result,
  agent.text,
  agent.message?.content,
]
  .map((candidate) => normalizeStructuredCandidate(candidate))
  .find((candidate) => isStructuredToolResult(candidate)) || null;

const detectedIntent = detectIntent(event.commandText || '');
let resultText = toText(structuredOutput?.resultText || rawOutput);

if (!resultText) {
  if (detectedIntent === 'smallTalk') {
    resultText = `Mình đây nè. Bạn có thể thử: ${stableCommands.join(', ')}.`;
  } else {
    resultText = `Hiện mình hỗ trợ ổn nhất các lệnh: ${stableCommands.join(', ')}. Nhóm demo: ${demoCommands.join(', ')}.`;
  }
}

const previousTurns = normalizeTurns(context.memory?.turns || []);
const nowIso = toText(config.nowIso || new Date().toISOString());
const newTurn = {
  user: trimText(event.commandText || '', memoryUserChars),
  assistant: trimText(resultText, memoryAssistantChars),
  at: nowIso,
};
const turns = [...previousTurns, newTurn]
  .filter((turn) => turn.user || turn.assistant)
  .slice(-memoryMaxTurns);

const currentIntent = JSON.stringify({
  intent: detectedIntent,
  previousIntent: toText(context.memory?.intent || ''),
  turns,
  memoryUpdatedAt: nowIso,
});

const deliveryPlan = normalizeDeliveryPlan(structuredOutput?.deliveryPlan, resultText);

return [
  {
    json: {
      toolName: toText(structuredOutput?.toolName || ''),
      resultText,
      currentIntent,
      deliveryPlan,
    },
  },
];

const envelope = $('Build Agent Delivery Envelope').first().json || {};
const deliveryPlan = envelope.deliveryPlan && typeof envelope.deliveryPlan === 'object'
  ? envelope.deliveryPlan
  : {};
const destinations = Array.isArray(deliveryPlan.destinations) ? deliveryPlan.destinations : [];
const messages = Array.isArray(deliveryPlan.messages) ? deliveryPlan.messages : [];
const resultText = String(envelope.resultText || '').trim() || 'Đã nhận lệnh.';

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function hasDestination(message, destinationType) {
  const destinationTypes = Array.isArray(message?.destinations) ? message.destinations : [];
  return destinationTypes.some((type) => toText(type) === destinationType);
}

const hasReplyDestination = destinations.some((destination) => toText(destination?.type || '') === 'reply');
const replyMessages = messages.filter((message) => hasDestination(message, 'reply') && message?.payload && typeof message.payload === 'object');
const preferredPayload = replyMessages.find((message) => toText(message.type) === 'text')?.payload || replyMessages[0]?.payload || null;

return [
  {
    json: {
      hasReplyDestination,
      responseBody: hasReplyDestination ? preferredPayload || { text: resultText } : {},
    },
  },
];

const prepare = $('Prepare GGChat Delivery Messages').first().json || {};
const responses = $input.all();
const requestCount = Number(prepare.ggChatRequestCount || 0);
const responseItems = requestCount > 0
  ? responses.filter((item) => Number(item.json?.statusCode || 0) > 0)
  : [];

const successCount = responseItems.filter((item) => Number(item.json?.statusCode || 0) < 400).length;
const failureCount = responseItems.filter((item) => Number(item.json?.statusCode || 0) >= 400).length;
const missingCount = Math.max(0, requestCount - responseItems.length);

let ggChatDeliveryStatus = 'skipped';
if (requestCount === 0) {
  ggChatDeliveryStatus = 'skipped';
} else if (successCount === requestCount) {
  ggChatDeliveryStatus = 'delivered';
} else if (successCount > 0) {
  ggChatDeliveryStatus = 'partial';
} else {
  ggChatDeliveryStatus = 'failed';
}

return [
  {
    json: {
      ggChatDeliveryStatus,
      ggChatMessageCount: requestCount,
      ggChatSuccessCount: successCount,
      ggChatFailureCount: failureCount,
      ggChatMissingCount: missingCount,
      ggChatThreadKey: String(prepare.ggChatThreadKey || '').trim(),
      ggChatDeliverySkipReason: String(prepare.ggChatDeliverySkipReason || '').trim(),
    },
  },
];

return {
  triggerSource: 'manual',
  channel: 'manualTrigger',
  commandText: 'release sprint',
  actorId: 'manual-release-trigger',
  actorDisplayName: 'Manual Trigger Release Sprint',
  spaceId: 'manual-trigger-space',
  threadKey: 'manual-release-sprint',
  sessionId: 'manual-trigger-space:manual-release-sprint',
};

const payload = $json && typeof $json === 'object' ? $json : {};
const commandText = String(payload.chatInput || payload.text || payload.message?.text || '').trim() || 'check sprint';
const actorId = String(payload.actorId || payload.userId || payload.user?.id || 'n8n-chat-user').trim();
const actorDisplayName = String(payload.actorDisplayName || payload.userName || payload.user?.name || 'N8N Chat User').trim();
const rawSpaceId = String(payload.spaceId || '').trim();
const rawThreadKey = String(payload.threadKey || payload.thread || '').trim();
const rawSessionId = String(payload.sessionId || '').trim();
const spaceId = rawSpaceId || 'n8n-chat';
const threadKey = rawThreadKey || rawSessionId || 'local-chat-thread';
const sessionId = rawSessionId || `${spaceId}:${threadKey}`;

return {
  triggerSource: 'chat',
  channel: 'n8nChatTrigger',
  commandText,
  actorId,
  actorDisplayName,
  spaceId,
  threadKey,
  sessionId,
};

const envelope = $('Build Agent Delivery Envelope').first().json || {};
const event = $('Config Main').first().json || {};
const config = event.config || {};
const deliveryPlan = envelope.deliveryPlan && typeof envelope.deliveryPlan === 'object'
  ? envelope.deliveryPlan
  : {};
const destinations = Array.isArray(deliveryPlan.destinations) ? deliveryPlan.destinations : [];
const rawMessages = Array.isArray(deliveryPlan.messages) ? deliveryPlan.messages : [];
const baseUrl = String(config.ggChatWebhookUrl || '').trim();
const replyOption = encodeURIComponent(
  String(config.googleChatReplyOption || 'REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD').trim() || 'REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD',
);

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function slugify(value) {
  return toText(value)
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

function hasDestination(message, destinationType) {
  const destinationTypes = Array.isArray(message?.destinations) ? message.destinations : [];
  return destinationTypes.some((type) => toText(type) === destinationType);
}

function normalizeMessage(message, fallbackText) {
  if (!message || typeof message !== 'object') return null;

  const payload = message.payload && typeof message.payload === 'object'
    ? message.payload
    : (toText(message.text || fallbackText) ? { text: toText(message.text || fallbackText) } : null);

  if (!payload) return null;

  return {
    messageKey: toText(message.messageKey || message.key || 'message') || 'message',
    type: toText(message.type || (payload.cardsV2 ? 'googleChatCardV2' : 'text')) || 'text',
    destinations: Array.isArray(message.destinations) ? message.destinations : [],
    payload,
  };
}

const fallbackText = toText(envelope.resultText || 'Đã có kết quả xử lý.');
const hasPushDestination = destinations.some((destination) => toText(destination?.type || '') === 'pushGoogleChat');
const messages = rawMessages
  .map((message) => normalizeMessage(message, fallbackText))
  .filter((message) => message && hasDestination(message, 'pushGoogleChat'));

const threadConfig = deliveryPlan.thread && typeof deliveryPlan.thread === 'object'
  ? deliveryPlan.thread
  : {};
const seed = slugify(threadConfig.threadKeyHint || event.threadKey || envelope.toolName || 'momo-ai-assistant') || 'momo-ai-assistant';
const uniqueSuffix = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
const finalThreadKey = String(event.threadKey || '').trim() || `${seed}-${uniqueSuffix}`.slice(0, 120);

let ggChatRequests = [];
let ggChatDeliverySkipReason = '';

if (!hasPushDestination) {
  ggChatDeliverySkipReason = 'No pushGoogleChat destination requested.';
} else if (!baseUrl) {
  ggChatDeliverySkipReason = 'ggChatWebhookUrl is not configured.';
} else if (messages.length === 0) {
  ggChatDeliverySkipReason = 'No Google Chat messages matched the requested destinations.';
} else {
  const separator = baseUrl.includes('?') ? '&' : '?';
  const requestUrl = `${baseUrl}${separator}threadKey=${encodeURIComponent(finalThreadKey)}&messageReplyOption=${replyOption}`;
  ggChatRequests = messages.map((message, index) => ({
    requestIndex: index,
    messageKey: message.messageKey,
    messageType: message.type,
    requestBody: message.payload,
    requestUrl,
    finalThreadKey,
  }));
}

return [
  {
    json: {
      ggChatDeliveryEnabled: ggChatRequests.length > 0,
      ggChatRequestCount: ggChatRequests.length,
      ggChatRequests,
      ggChatDeliverySkipReason,
      ggChatThreadKey: finalThreadKey,
    },
  },
];

const requests = $('Prepare GGChat Delivery Messages').first().json?.ggChatRequests;
const safeRequests = Array.isArray(requests) ? requests : [];

return safeRequests.map((request, requestIndex) => ({
  json: {
    requestIndex,
    ...request,
  },
}));

const envelope = $('Build Agent Delivery Envelope').first().json || {};
const reply = $('Build Reply Response').first().json || {};
const delivery = $input.first()?.json || {};
const event = $('Config Main').first().json || {};
const responseBody = reply.responseBody && typeof reply.responseBody === 'object'
  ? reply.responseBody
  : {};
const hasReplyDestination = Boolean(reply.hasReplyDestination);
const channel = String(event.channel || '').trim();

if (hasReplyDestination && Object.keys(responseBody).length > 0) {
  return [{ json: responseBody }];
}

if (channel === 'googleChat' || channel === 'n8nChatTrigger') {
  return [{ json: {} }];
}

return [
  {
    json: {
      status: String(delivery.ggChatDeliveryStatus || 'skipped'),
      channel,
      resultText: String(envelope.resultText || '').trim(),
      threadKey: String(delivery.ggChatThreadKey || event.threadKey || '').trim(),
      messageCount: Number(delivery.ggChatMessageCount || 0),
      successCount: Number(delivery.ggChatSuccessCount || 0),
      failureCount: Number(delivery.ggChatFailureCount || 0),
      skipReason: String(delivery.ggChatDeliverySkipReason || '').trim(),
    },
  },
];
